INSERT INTO sops (id, title, description, category, department, status, tags, created_by)
INSERT INTO sop_steps (sop_id, sort_order, title, content, tip, warning) VALUES
('a0a0a0a0-0001-4000-8000-000000000001', 0, 'Logging In', 'Open the app URL in your browser (Chrome recommended). Enter your email and password. If this is your first time, check your email for a verification link before signing in.', 'Bookmark the app URL for quick access. On mobile, use "Add to Home Screen" for an app-like experience.', NULL),
('a0a0a0a0-0001-4000-8000-000000000001', 1, 'Understanding the Sidebar', E'The left sidebar is your main navigation hub:\n\u2022 Dashboard \u2014 business metrics overview\n\u2022 Jobs \u2014 all active and completed jobs\n\u2022 Quotes \u2014 customer proposals\n\u2022 Customers \u2014 contact database\n\u2022 Messages \u2014 customer communications\n\u2022 Action Items \u2014 task list\n\u2022 Inventory \u2014 garment stock\n\u2022 Knowledge \u2014 SOPs, checklists, training\n\u2022 Financials \u2014 revenue and profitability\n\u2022 Team \u2014 workers and overhead\n\u2022 Settings \u2014 business config\n\u2022 Production modules (Embroidery, Screen Print, DTF, Leather)', 'Click the collapse arrow to minimize the sidebar for more screen space.', NULL),
('a0a0a0a0-0001-4000-8000-000000000001', 2, 'Reading the Dashboard', E'The Dashboard gives you an at-a-glance view:\n\u2022 Revenue Chart \u2014 monthly revenue trends\n\u2022 Job Volume Chart \u2014 jobs flowing through\n\u2022 Service Breakdown \u2014 pie chart of job types\n\u2022 Stage Breakdown \u2014 where jobs sit in the pipeline\n\u2022 Due Soon Widget \u2014 upcoming due dates\n\nUse date range filters to zoom in on specific periods.', 'Check the Dashboard at the start of each day to know what is coming due.', NULL);
INSERT INTO sops (id, title, description, category, department, status, tags, created_by)
INSERT INTO sop_steps (sop_id, sort_order, title, content, tip, warning) VALUES
('a0a0a0a0-0002-4000-8000-000000000001', 0, 'Creating a New Job', E'Navigate to Jobs and click "+ New Job". Fill in:\n\u2022 Customer Name (required)\n\u2022 Service Type\n\u2022 Description\n\u2022 Quantity\n\u2022 Sale Price\n\u2022 Order Number / Invoice Number\n\u2022 Due Date\n\nClick "Create Job" to save. The job starts in the "Received" stage.', 'Link the job to an existing customer record to build order history.', NULL),
('a0a0a0a0-0002-4000-8000-000000000001', 1, 'Understanding Job Stages', E'Every job moves through a defined pipeline:\n1. Received\n2. Art Prep\n3. Art Approved\n4. Prepress\n5. In Production\n6. Quality Check\n7. Ready for Pickup\n8. Shipped/Delivered\n\nUse the "Advance Stage" button to move jobs forward. The Kanban board view lets you drag jobs between stages.', NULL, 'Only advance a job when the work for that stage is truly complete. Stage history is permanent.'),
('a0a0a0a0-0002-4000-8000-000000000001', 2, 'Adding Garments to a Job', E'In the job detail sheet, scroll to Garments:\n\u2022 Click "+ Add Garment"\n\u2022 Enter style number \u2014 pricing pulls from the product catalog\n\u2022 Select color, sizes, quantities per size\n\u2022 Set decoration type and placement\n\u2022 Markup and sell price calculate automatically', 'Use the Garment Search dialog to find styles across SanMar and S&S Activewear.', NULL),
('a0a0a0a0-0002-4000-8000-000000000001', 3, 'Job Photos', E'Upload photos directly to a job card:\n\u2022 Click the camera icon or "+ Add Photo"\n\u2022 On mobile, this opens your device camera\n\u2022 Add descriptions for context\n\nPhotos appear in production module detail sheets.', 'Take photos of finished products before packaging for quality documentation.', NULL),
('a0a0a0a0-0002-4000-8000-000000000001', 4, 'Attaching Checklists to Jobs', E'In the Checklists panel:\n\u2022 Click "Attach" to see available templates\n\u2022 Templates matching the job service type are marked "Suggested"\n\u2022 Check items off as you complete them\n\u2022 Use arrow buttons to reorder, + button to insert items between existing ones', 'Attach checklists at the start of a job so nothing gets missed.', NULL),
('a0a0a0a0-0002-4000-8000-000000000001', 5, 'Paid Date & Auto Due Date', 'When a customer pays, set the "Paid At" date. The system auto-calculates a due date 13 business days out. You can override with a manual due date. Jobs with due dates appear in the "Due Soon" dashboard widget.', 'Set the paid date as soon as payment is confirmed \u2014 it triggers production priority.', NULL);
INSERT INTO sops (id, title, description, category, department, status, tags, created_by)
INSERT INTO sop_steps (sop_id, sort_order, title, content, tip, warning) VALUES
('a0a0a0a0-0003-4000-8000-000000000001', 0, 'Navigating to Your Production Module', E'Each department has its own sidebar page:\n\u2022 Embroidery \u2014 thread setup, hoop sizes, stitch counts, Barudan settings\n\u2022 Screen Print \u2014 platen setup, ink colors, flash/cure settings\n\u2022 DTF \u2014 press temp/time, fabric type, peel settings\n\u2022 Leather \u2014 laser power/speed/frequency, material type, patch dimensions', NULL, NULL),
('a0a0a0a0-0003-4000-8000-000000000001', 1, 'Saving a Recipe', E'When you dial in settings for a job, save them:\n\u2022 Click "+ New Recipe" or save from within a job\n\u2022 Fill in all machine settings\n\u2022 Link to the current job and customer\n\u2022 Add notes about what worked\n\nRecipes are searchable by customer, job, or settings.', 'Always save a recipe after a successful production run.', NULL),
('a0a0a0a0-0003-4000-8000-000000000001', 2, 'Reviewing Saved Jobs', E'Click any saved job to open a read-only detail sheet showing:\n\u2022 All recipe settings used\n\u2022 Original job photos\n\u2022 Customer name and details\n\u2022 Operator notes\n\nSaved jobs are historical records and cannot be edited.', 'Before starting a reorder, always pull up the saved job to verify settings.', NULL),
('a0a0a0a0-0003-4000-8000-000000000001', 3, 'Loading a Recipe for Reorders', E'When a customer reorders:\n1. Find the original recipe in the production module\n2. Click "Load Recipe" to pre-fill settings\n3. Adjust if materials or equipment changed\n4. Save the new recipe linked to the new job', NULL, NULL);
INSERT INTO sops (id, title, description, category, department, status, tags, created_by)
INSERT INTO sop_steps (sop_id, sort_order, title, content, tip, warning) VALUES
('a0a0a0a0-0004-4000-8000-000000000001', 0, 'Why We Track Time', E'Time tracking drives true job profitability:\n\u2022 Labor cost = time \u00d7 worker hourly rate\n\u2022 Profitability reports show if we make or lose money\n\u2022 Production planning uses real time data\n\u2022 Customer pricing accuracy depends on real labor data', NULL, 'Inaccurate time entries lead to bad pricing. If you forget to log, jobs look more profitable than they are.'),
('a0a0a0a0-0004-4000-8000-000000000001', 1, 'How to Log Time', E'Open a job card, find Time Entries:\n\u2022 Click "+ Add Time Entry"\n\u2022 Select the worker\n\u2022 Enter hours and minutes\n\u2022 Add notes (e.g., "Setup and first run \u2014 150 pieces")\n\u2022 Optionally link to a specific line item\n\u2022 Click Save', 'Log time as soon as you finish a task while it is fresh.', NULL),
('a0a0a0a0-0004-4000-8000-000000000001', 2, 'Best Practices', E'\u2022 Log time PER JOB, not in bulk\n\u2022 Include setup time, not just run time\n\u2022 If you switch jobs, log each separately\n\u2022 Round to the nearest 5 minutes\n\u2022 Always add notes\n\u2022 Each person logs their own time\n\u2022 Log rework time too \u2014 it matters for costing', 'If you spent more than 5 minutes on it, log it.', NULL),
('a0a0a0a0-0004-4000-8000-000000000001', 3, 'Viewing Time Reports', E'Time data rolls up in:\n\u2022 Job Card \u2014 total time with all entries\n\u2022 Job Cost Summary \u2014 labor cost calculated\n\u2022 Financials \u2014 labor in profitability\n\u2022 Team page \u2014 admin view of all worker time', NULL, NULL);
INSERT INTO sops (id, title, description, category, department, status, tags, created_by)
INSERT INTO sop_steps (sop_id, sort_order, title, content, tip, warning) VALUES
('a0a0a0a0-0005-4000-8000-000000000001', 0, 'Adding a Customer', E'Navigate to Customers, click "+ Add Customer":\n\u2022 Name (required)\n\u2022 Company\n\u2022 Email and Phone\n\u2022 Address\n\u2022 Preferred contact method\n\u2022 Referral source\n\u2022 Tags (e.g., "repeat", "nonprofit")\n\u2022 Notes', 'Always check if the customer already exists before creating a new one.', NULL),
('a0a0a0a0-0005-4000-8000-000000000001', 1, 'Customer History & Revenue', E'Each customer record tracks:\n\u2022 Total orders and total revenue\n\u2022 First and last order dates\n\u2022 All linked jobs and quotes\n\nHistory builds automatically as you link customers to jobs.', 'When a customer calls, pull up their record first.', NULL);
INSERT INTO sops (id, title, description, category, department, status, tags, created_by)
INSERT INTO sop_steps (sop_id, sort_order, title, content, tip, warning) VALUES
('a0a0a0a0-0006-4000-8000-000000000001', 0, 'Creating a Quote', E'Navigate to Quotes, click "+ New Quote":\n\u2022 Customer Name\n\u2022 Company, email, phone\n\u2022 Delivery method\n\u2022 Payment terms\n\u2022 Requested date\n\u2022 Notes\n\nAuto-generated quote number (Q-XXXX).', NULL, NULL),
('a0a0a0a0-0006-4000-8000-000000000001', 1, 'Adding Line Items', E'Each quote has line items:\n\u2022 Click "+ Add Line Item"\n\u2022 Select service type\n\u2022 Enter style number for catalog pricing\n\u2022 Set quantity, sizes, colors\n\u2022 Garment cost + markup = sell price\n\u2022 Add decoration cost\n\u2022 Line total updates automatically with tax', 'Use the product catalog search for accurate garment costs.', NULL),
('a0a0a0a0-0006-4000-8000-000000000001', 2, 'Quote Lifecycle', E'Statuses:\n\u2022 Draft \u2014 being built\n\u2022 Sent \u2014 delivered to customer\n\u2022 Approved \u2014 customer accepted\n\u2022 Rejected \u2014 customer declined\n\u2022 Converted \u2014 turned into a job\n\nUse the follow-up system for quotes needing attention.', NULL, NULL),
('a0a0a0a0-0006-4000-8000-000000000001', 3, 'Converting a Quote to a Job', E'When approved:\n1. Open the quote, click "Convert to Job"\n2. System creates a new job pre-filled with quote details\n3. Garment line items transfer\n4. Quote status updates to "Converted"', 'Review the converted job to make sure all details transferred correctly.', NULL);
INSERT INTO sops (id, title, description, category, department, status, tags, created_by)
INSERT INTO sop_steps (sop_id, sort_order, title, content, tip, warning) VALUES
('a0a0a0a0-0007-4000-8000-000000000001', 0, 'Sending a Message', E'From Messages or a customer/job detail sheet:\n\u2022 Click "Send Message"\n\u2022 Select channel \u2014 Email or SMS\n\u2022 Choose recipient\n\u2022 Write message or select a template\n\u2022 For email, add a subject line\n\u2022 Click Send\n\nAll messages are logged with timestamps.', 'Use templates for common messages to save time.', NULL),
('a0a0a0a0-0007-4000-8000-000000000001', 1, 'Using Message Templates', E'The Template Library has pre-built messages:\n\u2022 Organized by category\n\u2022 Click to preview and insert\n\u2022 Fill in variable fields before sending\n\nAdmins can create and edit templates.', 'If you type the same message repeatedly, ask an admin to create a template.', NULL);
INSERT INTO sops (id, title, description, category, department, status, tags, created_by)
INSERT INTO sop_steps (sop_id, sort_order, title, content, tip, warning) VALUES
('a0a0a0a0-0008-4000-8000-000000000001', 0, 'Creating Action Items', E'Navigate to Action Items, click "+ Quick Capture":\n\u2022 Title\n\u2022 Priority (normal, high, urgent)\n\u2022 Due date\n\u2022 Link to job, quote, or customer\n\u2022 Add checklist for multi-step tasks\n\u2022 Notes', 'Link action items to jobs whenever possible.', NULL),
('a0a0a0a0-0008-4000-8000-000000000001', 1, 'Managing Action Items', E'Statuses:\n\u2022 Open \u2014 needs attention\n\u2022 In Progress \u2014 being worked on\n\u2022 Completed \u2014 done\n\nReview at the start and end of each day. Overdue items are highlighted.', 'Use Quick Capture to jot tasks fast without leaving your current page.', NULL);
INSERT INTO sops (id, title, description, category, department, status, tags, created_by)
INSERT INTO sop_steps (sop_id, sort_order, title, content, tip, warning) VALUES
('a0a0a0a0-0009-4000-8000-000000000001', 0, 'Finding SOPs', E'Navigate to Knowledge. The SOPs tab shows all procedures:\n\u2022 Search by title or keyword\n\u2022 Filter by department and category\n\u2022 Click any SOP to read step-by-step\n\nPublished = official. Draft = work in progress.', 'If you cannot find an SOP, ask your lead \u2014 it may need to be created.', NULL),
('a0a0a0a0-0009-4000-8000-000000000001', 1, 'Using Checklists', E'The Checklists tab has reusable templates:\n\u2022 Browse by department and category\n\u2022 Attach to individual jobs\n\u2022 Check items off as completed\n\u2022 Progress visible to the whole team\n\u2022 Reorder with arrows, insert with + button', NULL, 'Do NOT skip checklist items because you are in a hurry. Skipped steps cause rework.'),
('a0a0a0a0-0009-4000-8000-000000000001', 2, 'Training Plans', E'The Training tab is for onboarding:\n\u2022 Plans bundle SOPs and checklists into a learning path\n\u2022 Each plan targets a role and department\n\u2022 Progress tracked as you complete items\n\u2022 Trainer sees progress and signs off\n\nNew team members: your training plan is your roadmap.', NULL, NULL);
INSERT INTO sops (id, title, description, category, department, status, tags, created_by)
INSERT INTO sop_steps (sop_id, sort_order, title, content, tip, warning) VALUES
('a0a0a0a0-000a-4000-8000-000000000001', 0, 'Adding Inventory', E'Navigate to Inventory, click "+ Add Item":\n\u2022 Style Number (required)\n\u2022 Brand, Color, Size\n\u2022 Quantity\n\u2022 Unit Cost\n\u2022 Location / Bin\n\u2022 Notes', 'Do a physical count before updating \u2014 the system is only as accurate as the data.', NULL),
('a0a0a0a0-000a-4000-8000-000000000001', 1, 'Using Inventory with Jobs', E'When adding garments to a job:\n\u2022 Style numbers from inventory appear in search\n\u2022 Unit cost pre-fills from inventory\n\u2022 Track pulled-from-stock vs. ordered fresh', NULL, NULL);
INSERT INTO sops (id, title, description, category, department, status, tags, created_by)
INSERT INTO sop_steps (sop_id, sort_order, title, content, tip, warning) VALUES
('a0a0a0a0-000b-4000-8000-000000000001', 0, 'Understanding the Financials Page', E'The Financials page provides:\n\u2022 Revenue by Service\n\u2022 Profitability Insights \u2014 sale price vs. total costs\n\u2022 Sales Tax Report\n\u2022 Bulk Reclassify tool for historical jobs', 'Review financials monthly to spot trends.', 'Financial data requires complete sale prices, material costs, and time entries to be accurate.'),
('a0a0a0a0-000b-4000-8000-000000000001', 1, 'Job Profitability', E'Each job''s profitability:\n\u2022 Revenue = Sale Price\n\u2022 Costs = Material + Labor + Overhead\n\u2022 Profit = Revenue - Costs\n\u2022 Margin = Profit / Revenue \u00d7 100\n\nThe Job Cost Summary on each job card shows this breakdown.', 'If a job type consistently shows thin margins, raise prices or find efficiency gains.', NULL);
INSERT INTO sops (id, title, description, category, department, status, tags, created_by)
INSERT INTO sop_steps (sop_id, sort_order, title, content, tip, warning) VALUES
('a0a0a0a0-000c-4000-8000-000000000001', 0, 'Daily Expectations', E'Every team member is expected to:\n\u2022 Check the Dashboard at shift start\n\u2022 Review and update Action Items\n\u2022 Log time within 30 minutes of completing work\n\u2022 Advance job stages as work completes\n\u2022 Complete all attached checklist items\n\u2022 Take and upload production photos', NULL, 'If you are not logging time and advancing stages in real time, the system cannot help the team plan.'),
('a0a0a0a0-000c-4000-8000-000000000001', 1, 'Data Quality Standards', E'\u2022 Every job must have: customer name, service type, quantity, sale price\n\u2022 Every completed job must have: time entries, material costs, stage history\n\u2022 Customer records should have: email OR phone (preferably both)\n\u2022 Recipes saved after every successful run\n\u2022 Photos taken of finished goods before packaging', 'Data entry is part of the job, not extra work. 2 minutes now saves hours later.', NULL),
('a0a0a0a0-000c-4000-8000-000000000001', 2, 'When You Get Stuck', E'\u2022 Check Knowledge for an SOP\n\u2022 Ask your lead before guessing\n\u2022 Report system issues \u2014 don''t work around them\n\u2022 Suggest process improvements \u2014 we update SOPs when better methods are found\n\nThis system is built for you. The more you use it correctly, the more it helps everyone.', NULL, NULL);
INSERT INTO checklist_templates (id, title, description, category, department, items, created_by)
INSERT INTO training_plans (id, title, description, department, role, sop_ids, checklist_template_ids, created_by)
